-- Additive columns used by the listing form
alter table public.ads add column if not exists item_type text;
alter table public.subcategories add column if not exists slug text;
alter table public.subcategories add column if not exists sort_order int default 0;
alter table public.subcategories add column if not exists is_active boolean default true;
create unique index if not exists subcategories_cat_slug_uidx on public.subcategories (category_id, slug);

-- Item types ("type of item" for each category / subcategory)
create table if not exists public.item_types (
  id uuid primary key default gen_random_uuid(),
  category_slug text not null,
  subcategory_slug text,
  name text not null,
  slug text not null,
  sort_order int not null default 0,
  created_at timestamptz not null default now(),
  unique (category_slug, subcategory_slug, slug)
);
alter table public.item_types enable row level security;
drop policy if exists "Item types viewable by everyone" on public.item_types;
create policy "Item types viewable by everyone" on public.item_types for select using (true);
drop policy if exists "Admins manage item types" on public.item_types;
do $$ begin
  if exists (select 1 from pg_proc where proname = 'is_admin') then
    execute 'create policy "Admins manage item types" on public.item_types for all using (public.is_admin(auth.uid())) with check (public.is_admin(auth.uid()))';
  end if;
end $$;
grant select on public.item_types to anon, authenticated;

